using UnityEngine;

public class AudioExample : MonoBehaviour
{
    // Audio components
    public AudioSource audioSource;
    public AudioClip jumpSound;
    public AudioClip coinSound;
    public AudioClip hitSound;
    public AudioClip deathSound;
    public AudioClip backgroundMusic;

    // Audio settings
    public float masterVolume = 1f;
    public float sfxVolume = 1f;
    public float musicVolume = 0.8f;

    void Start()
    {
        // Get AudioSource if not assigned
        if (audioSource == null)
        {
            audioSource = GetComponent<AudioSource>();
            if (audioSource == null)
            {
                audioSource = gameObject.AddComponent<AudioSource>();
            }
        }

        // Set up audio source
        audioSource.loop = false;
        audioSource.playOnAwake = false;
        audioSource.volume = masterVolume * musicVolume;

        // Play background music
        if (backgroundMusic != null)
        {
            audioSource.clip = backgroundMusic;
            audioSource.loop = true;
            audioSource.Play();
            Debug.Log("Background music started!");
        }

        Debug.Log("Audio system initialized!");
    }

    void Update()
    {
        // Test sounds with keys
        if (Input.GetKeyDown(KeyCode.Alpha1))
        {
            PlaySound(jumpSound, sfxVolume);
        }
        if (Input.GetKeyDown(KeyCode.Alpha2))
        {
            PlaySound(coinSound, sfxVolume);
        }
        if (Input.GetKeyDown(KeyCode.Alpha3))
        {
            PlaySound(hitSound, sfxVolume);
        }
    }

    // Play a sound effect
    public void PlaySound(AudioClip clip, float volume = 1f)
    {
        if (clip != null)
        {
            // Play one shot (non-looping)
            audioSource.PlayOneShot(clip, volume * masterVolume * sfxVolume);
            Debug.Log("Playing sound: " + clip.name);
        }
        else
        {
            Debug.LogWarning("Audio clip is null!");
        }
    }

    // Play a sound with pitch variation
    public void PlaySoundVaried(AudioClip clip, float minPitch = 0.9f, float maxPitch = 1.1f)
    {
        if (clip != null)
        {
            float originalPitch = audioSource.pitch;
            audioSource.pitch = Random.Range(minPitch, maxPitch);
            PlaySound(clip);
            audioSource.pitch = originalPitch;
        }
    }

    // Play a sound from a specific position (3D audio)
    public void PlaySoundAtPosition(AudioClip clip, Vector3 position, float volume = 1f)
    {
        if (clip != null)
        {
            AudioSource.PlayClipAtPoint(clip, position, volume * masterVolume * sfxVolume);
        }
    }

    // Control music
    public void PlayMusic(AudioClip clip, bool loop = true)
    {
        if (clip != null)
        {
            audioSource.clip = clip;
            audioSource.loop = loop;
            audioSource.Play();
        }
    }

    public void StopMusic()
    {
        audioSource.Stop();
    }

    public void PauseMusic()
    {
        audioSource.Pause();
    }

    public void ResumeMusic()
    {
        audioSource.UnPause();
    }

    // Volume controls
    public void SetMasterVolume(float volume)
    {
        masterVolume = Mathf.Clamp01(volume);
        UpdateVolumes();
    }

    public void SetSFXVolume(float volume)
    {
        sfxVolume = Mathf.Clamp01(volume);
        UpdateVolumes();
    }

    public void SetMusicVolume(float volume)
    {
        musicVolume = Mathf.Clamp01(volume);
        UpdateVolumes();
    }

    void UpdateVolumes()
    {
        audioSource.volume = masterVolume * musicVolume;
    }
}

