using UnityEngine;

public class AudioError : MonoBehaviour
{
    public AudioSource audioSource;

    void Start()
    {
        // Forgot to check if audioSource is null
        audioSource.Play();  // NullReferenceException!
    }
}

phase2.explanation:
You're trying to use an AudioSource that was never assigned.

**The fix:**
```csharp
void Start()
{
    if (audioSource != null)
    {
        audioSource.Play();
    }
    else
    {
        Debug.LogError("AudioSource is not assigned!");
    }
}
```

**Sharp-chan says:**
"Always check if AudioSource is assigned before using it."
